/** Get FNS offices for given cities (subset of RUSSIAN_CITIES) */
export function getFNSForCities(cities: string[]): FNSOffice[] {
  if (cities.length === 0) return [];
  return FNS_OFFICES.filter((o) => cities.includes(o.city));
}

/** Get unique city names that have at least one FNS entry */
export const FNS_CITIES = [...new Set(FNS_OFFICES.map((o) => o.city))].sort((a, b) =>
  a.localeCompare(b, 'ru'),
);